/* ── QR Code Visual ── */
function QRCode({ url, size = 160 }) {
  const cells = 13
  const cellSize = size / cells
  const hash = url.split('').reduce((a, c) => ((a << 5) - a + c.charCodeAt(0)) | 0, 0)
  const bits = []
  for (let i = 0; i < cells * cells; i++) {
    bits.push(((hash * (i + 1) * 2654435761) >>> 0) % 4 < 2)
  }
  const setFinder = (r, c) => {
    for (let dr = 0; dr < 3; dr++) for (let dc = 0; dc < 3; dc++) {
      bits[(r + dr) * cells + (c + dc)] = dr === 0 || dr === 2 || dc === 0 || dc === 2 || (dr === 1 && dc === 1)
    }
  }
  setFinder(0, 0); setFinder(0, cells - 3); setFinder(cells - 3, 0)
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ borderRadius: 10, background: '#fff' }}>
      {bits.map((on, i) => on ? (
        <rect key={i} x={(i % cells) * cellSize + 2} y={Math.floor(i / cells) * cellSize + 2}
          width={cellSize - 1.2} height={cellSize - 1.2} rx={1.2} fill={T.bg} />
      ) : null)}
    </svg>
  )
}

